import { useParams, useNavigate } from "react-router-dom";
import { useState, useEffect } from "react";
import api from "../api";
import "./styles/Books.css";
const bookExtraDetails = {
  "Harry Potter": {
    about:
      "Harry Potter is a fantasy novel that follows the journey of a young wizard discovering his magical heritage and destiny at Hogwarts School of Witchcraft and Wizardry.",
    authorInfo:
      "J.K. Rowling is a British author best known for the Harry Potter series, which became one of the best-selling book franchises in history.",
    reviews: [
      "⭐️⭐️⭐️⭐️⭐️ Magical and unforgettable.",
      "⭐️⭐️⭐️⭐️ A classic fantasy for all ages.",
      "⭐️⭐️⭐️⭐️⭐️ The world-building is phenomenal."
    ]
  },

  "The Hobbit": {
    about:
      "The Hobbit follows Bilbo Baggins on an unexpected adventure filled with dragons, treasure, and courage.",
    authorInfo:
      "J.R.R. Tolkien was an English writer and professor, famous for high fantasy works.",
    reviews: [
      "⭐️⭐️⭐️⭐️⭐️ A timeless adventure.",
      "⭐️⭐️⭐️⭐️ Perfect introduction to fantasy."
    ]
  }
};
function BooksDetails() {
  const { title, author, cover } = useParams();
  const navigate = useNavigate();

  const decodedTitle = decodeURIComponent(title);

  const [isBorrowed, setIsBorrowed] = useState(false);

  useEffect(() => {
    api.get(`/books/${encodeURIComponent(decodedTitle)}/status`)
      .then(res => setIsBorrowed(res.data.isBorrowed))
      .catch(() => setIsBorrowed(false));
  }, [decodedTitle]);

  const borrowBook = async () => {
    try {
      await api.post(`/books/${encodeURIComponent(decodedTitle)}/borrow`);
      setIsBorrowed(true);
    } catch {}
  };

  const returnBook = async () => {
    try {
      await api.post(`/books/${encodeURIComponent(decodedTitle)}/return`);
      setIsBorrowed(false);
    } catch {}
  };

  return (
    <div className="books-page">
      <div className="detail-card">
        <img src={decodeURIComponent(cover)} alt={decodedTitle} />

        <h2>{decodedTitle}</h2>
        <p>{decodeURIComponent(author)}</p>

        <p className="status">
          Status:{" "}
          <span className={isBorrowed ? "not-avail" : "avail"}>
            {isBorrowed ? "Not Available" : "Available"}
          </span>
        </p>

        {!isBorrowed ? (
          <button className="main-cta" onClick={borrowBook}>
            Borrow Book
          </button>
        ) : (
          <button className="return-btn" onClick={returnBook}>
            Return Book
          </button>
        )}

        <button className="back-btn" onClick={() => navigate(-1)}>
          ← Back to Library
        </button>
      </div>
    </div>
  );
}

export default BooksDetails;
